class DataArea {
  #system;
  #path;
  #library;
  #name;
  constructor(system, path) {
    if (!system)
      throw new Error("DataArea requires an AS400 instance");
    if (!path)
      throw new Error("DataArea requires a path");
    this.#system = system;
    this.#path = path;
    const parsed = QSYSObjectPathName.parse(path);
    this.#library = parsed.library;
    this.#name = parsed.object;
  }
  get path() {
    return this.#path;
  }
  get library() {
    return this.#library;
  }
  get name() {
    return this.#name;
  }
  async readCharacter(offset = 0, length = -1) {
    const { ProgramCall: ProgramCall2 } = await Promise.resolve().then(() => (init_ProgramCall(), exports_ProgramCall));
    const { ProgramParameter: ProgramParameter2 } = await Promise.resolve().then(() => (init_ProgramParameter(), exports_ProgramParameter));
    const { CharConverter: CharConverter2 } = await Promise.resolve().then(() => (init_CharConverter(), exports_CharConverter));
    const ccsid147 = this.#system.getServerCCSID() || 37;
    const conv = new CharConverter2(ccsid147);
    const outLen = 4096;
    const qualName = Buffer.alloc(20, 64);
    conv.stringToByteArray(this.#name.toUpperCase()).copy(qualName, 0, 0, 10);
    conv.stringToByteArray(this.#library.toUpperCase()).copy(qualName, 10, 0, 10);
    const startPos = Buffer.alloc(4);
    startPos.writeInt32BE(length === -1 ? -1 : offset + 1, 0);
    const lenBuf = Buffer.alloc(4);
    lenBuf.writeInt32BE(length === -1 ? -1 : length, 0);
    const outLenBuf = Buffer.alloc(4);
    outLenBuf.writeInt32BE(outLen, 0);
    const errorCode = Buffer.alloc(8);
    errorCode.writeInt32BE(8, 0);
    const pc = new ProgramCall2(this.#system);
    pc.setProgram("/QSYS.LIB/QWCRDTAA.PGM", [
      new ProgramParameter2({ outputLength: outLen }),
      new ProgramParameter2({ inputData: outLenBuf }),
      new ProgramParameter2({ inputData: qualName }),
      new ProgramParameter2({ inputData: startPos }),
      new ProgramParameter2({ inputData: lenBuf }),
      new ProgramParameter2({ inputData: errorCode, outputLength: 8 })
    ]);
    const success = await pc.run();
    if (!success) {
      const msgs = pc.getMessageList();
      throw new AS400Error(`DataArea read failed: ${msgs[0]?.text ?? "unknown error"}`, { messageId: msgs[0]?.id, hostService: "COMMAND" });
    }
    const outBuf = pc.getParameterList()[0].getOutputData();
    if (outBuf && outBuf.length >= 36) {
      const dataType = conv.byteArrayToString(outBuf, 8, 1);
      const dataLen = outBuf.readInt32BE(19);
      if (dataLen > 0 && 36 + dataLen <= outBuf.length) {
        if (dataType === "C") {
          return conv.byteArrayToString(outBuf, 36, dataLen).trim();
        }
        return conv.byteArrayToString(outBuf, 36, dataLen).trim();
      }
    }
    return "";
  }
  async readDecimal() {
    const strVal = await this.readCharacter();
    return parseFloat(strVal) || 0;
  }
  async readLogical() {
    const strVal = await this.readCharacter();
    return strVal === "1" || strVal.toUpperCase() === "TRUE";
  }
  async writeCharacter(value2, offset = 0) {
    const safeValue = value2.replace(/'/g, "''");
    let cmd;
    if (offset === 0) {
      cmd = `CHGDTAARA DTAARA(${this.#library}/${this.#name}) VALUE('${safeValue}')`;
    } else {
      cmd = `CHGDTAARA DTAARA(${this.#library}/${this.#name} (${offset + 1} ${value2.length})) VALUE('${safeValue}')`;
    }
    const msgs = await this.#system.runCommand(cmd);
    const errMsg = msgs.find((m) => m.severity >= 30);
    if (errMsg) {
      throw new AS400Error(`DataArea write failed: ${errMsg.text}`, { messageId: errMsg.id, hostService: "COMMAND" });
    }
  }
  async writeDecimal(value2) {
    const cmd = `CHGDTAARA DTAARA(${this.#library}/${this.#name}) VALUE(${value2})`;
    const msgs = await this.#system.runCommand(cmd);
    const errMsg = msgs.find((m) => m.severity >= 30);
    if (errMsg) {
      throw new AS400Error(`DataArea writeDecimal failed: ${errMsg.text}`, { messageId: errMsg.id, hostService: "COMMAND" });
    }
  }
  async writeLogical(value2) {
    const cmd = `CHGDTAARA DTAARA(${this.#library}/${this.#name}) VALUE('${value2 ? "1" : "0"}')`;
    const msgs = await this.#system.runCommand(cmd);
    const errMsg = msgs.find((m) => m.severity >= 30);
    if (errMsg) {
      throw new AS400Error(`DataArea writeLogical failed: ${errMsg.text}`, { messageId: errMsg.id, hostService: "COMMAND" });
    }
  }
  async create(opts = {}) {
    const type147 = opts.type ?? "*CHAR";
    const len = opts.length ?? 100;
    const desc = opts.description ?? "";
    const safeDesc = desc.replace(/'/g, "''");
    const cmd = `CRTDTAARA DTAARA(${this.#library}/${this.#name}) TYPE(${type147}) LEN(${len})` + (safeDesc ? ` TEXT('${safeDesc}')` : "");
    const msgs = await this.#system.runCommand(cmd);
    const errMsg = msgs.find((m) => m.severity >= 30);
    if (errMsg) {
      throw new AS400Error(`DataArea create failed: ${errMsg.text}`, { messageId: errMsg.id, hostService: "COMMAND" });
    }
  }
  async delete() {
    const cmd = `DLTDTAARA DTAARA(${this.#library}/${this.#name})`;
    const msgs = await this.#system.runCommand(cmd);
    const errMsg = msgs.find((m) => m.severity >= 30);
    if (errMsg) {
      throw new AS400Error(`DataArea delete failed: ${errMsg.text}`, { messageId: errMsg.id, hostService: "COMMAND" });
    }
  }
}
